function actAddSubitem() {
    const input = document.getElementById('actDefSubitemInput');
    if (!input || !input.value.trim()) return;
    if (!window._actState.datos.subitems) window._actState.datos.subitems = [];
    window._actState.datos.subitems.push({ texto: input.value.trim(), completado: false });
    input.value = '';
    _actRenderSubitems();
}

function _actRenderSubitems() {
    const list = document.getElementById('actDefSubitemList');
    if (!list) return;
    const items = window._actState.datos.subitems || [];
    list.innerHTML = items.map((it, i) => `
        <div data-idx="${i}" style="display:flex;align-items:center;gap:8px;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.07);border-radius:10px;padding:10px 12px;">
            <span class="act-subitem-drag material-symbols-rounded" style="color:#475569;font-size:16px;flex-shrink:0;cursor:grab;touch-action:none;">drag_indicator</span>
            <span style="color:#e2e8f0;font-size:13px;flex:1;">${it.texto}</span>
            <button onclick="actEliminarSubitem(${i})" style="background:none;border:none;color:#64748b;cursor:pointer;padding:0;display:flex;">
                <span class="material-symbols-rounded" style="font-size:18px;">delete</span>
            </button>
        </div>`).join('');
    if (list._sortable) { list._sortable.destroy(); list._sortable = null; }
    if (window.Sortable) {
        list._sortable = new Sortable(list, {
            handle: '.act-subitem-drag',
            animation: 150,
            ghostClass: 'sortable-ghost',
            onEnd: function(evt) {
                const subitems = window._actState.datos.subitems;
                if (!subitems) return;
                const moved = subitems.splice(evt.oldIndex, 1)[0];
                subitems.splice(evt.newIndex, 0, moved);
                Array.from(list.children).forEach((el, i) => el.dataset.idx = i);
            }
        });
    }
}

function actEliminarSubitem(i) {
    if (window._actState.datos.subitems) window._actState.datos.subitems.splice(i, 1);
    _actRenderSubitems();
}

function _actRestaurarDefinicion() {
    const d = window._actState.datos;
    setTimeout(() => {
        if (d.nombre) { const el = document.getElementById('actDefNombre'); if(el) el.value = d.nombre; }
        if (d.desc) { const el = document.getElementById('actDefDesc'); if(el) el.value = d.desc; }
        if (d.nota) { const el = document.getElementById('actDefNota'); if(el) el.value = d.nota; }
        if (d.fecha) { const el = document.getElementById('actDefFecha'); if(el) { el.value = d.fecha; setTimeout(()=>{ if(typeof _calAct2ActualizarDisp==='function') _calAct2ActualizarDisp('actDefFecha'); },10); } }
        if (d.hora) { const el = document.getElementById('actDefHora'); if(el) el.value = d.hora; const disp = document.getElementById('actDefHoraDisp'); if(disp){ disp.textContent = d.hora; disp.style.color='#f1f5f9'; const btn=disp.closest('button'); if(btn) btn.style.borderColor='rgba(59,130,246,0.6)'; } }
        if (d.condicion) { const el = document.getElementById('actDefCondicion'); if(el) el.value = d.condicion; }
        if (d.objetivo) { const el = document.getElementById('actDefObjetivo'); if(el) el.value = d.objetivo; }
        if (d.unidad) { const el = document.getElementById('actDefUnidad'); if(el) el.value = d.unidad; }
        if (d.subitems) _actRenderSubitems();
    }, 50);
}
