            <div style="position:absolute;top:3px;left:${window._actState.datos.flexible?'23':'3'}px;width:18px;height:18px;border-radius:50%;background:white;transition:left 0.2s;box-shadow:0 1px 4px rgba(0,0,0,0.3);"></div>
