function _menuHabito(e, id) {
    e.stopPropagation();
    const prev = document.getElementById('_habitoMenu');
    if (prev) { prev.remove(); return; }
    const menu = document.createElement('div');
    menu.id = '_habitoMenu';
    menu.style.cssText = 'position:fixed;background:#1e293b;border:1px solid rgba(71,85,105,0.4);border-radius:14px;padding:6px;z-index:99999;min-width:160px;box-shadow:0 8px 32px rgba(0,0,0,0.5);';
    menu.innerHTML = `
        <button onclick="_menuHabitoAccion('editar','${id}')" style="width:100%;display:flex;align-items:center;gap:10px;padding:10px 12px;border:none;background:none;color:#e2e8f0;font-size:13px;font-weight:600;cursor:pointer;border-radius:9px;text-align:left;" onmouseover="this.style.background='rgba(255,255,255,0.07)'" onmouseout="this.style.background='none'">
            <span class="material-symbols-rounded" style="font-size:17px;color:#94a3b8;">edit</span> Editar
        </button>
        <button onclick="_menuHabitoAccion('archivar','${id}')" style="width:100%;display:flex;align-items:center;gap:10px;padding:10px 12px;border:none;background:none;color:#e2e8f0;font-size:13px;font-weight:600;cursor:pointer;border-radius:9px;text-align:left;" onmouseover="this.style.background='rgba(255,255,255,0.07)'" onmouseout="this.style.background='none'">
            <span class="material-symbols-rounded" style="font-size:17px;color:#64748b;">archive</span> Archivar
        </button>
        <div style="height:1px;background:rgba(71,85,105,0.3);margin:4px 0;"></div>
        <button onclick="_menuHabitoAccion('eliminar','${id}')" style="width:100%;display:flex;align-items:center;gap:10px;padding:10px 12px;border:none;background:none;color:#f87171;font-size:13px;font-weight:600;cursor:pointer;border-radius:9px;text-align:left;" onmouseover="this.style.background='rgba(239,68,68,0.1)'" onmouseout="this.style.background='none'">
            <span class="material-symbols-rounded" style="font-size:17px;">delete</span> Eliminar
        </button>`;
    document.body.appendChild(menu);
    const rect = e.currentTarget.getBoundingClientRect();
    let left = rect.right - menu.offsetWidth;
    let top = rect.bottom + 4;
    if (left < 8) left = 8;
    if (top + 150 > window.innerHeight) top = rect.top - 150;
    menu.style.left = left + 'px';
    menu.style.top = top + 'px';
    setTimeout(() => document.addEventListener('click', function _close() {
        document.getElementById('_habitoMenu')?.remove();
        document.removeEventListener('click', _close);
    }), 50);
}

function _menuHabitoAccion(accion, id) {
    document.getElementById('_habitoMenu')?.remove();
    if (accion === 'editar') {
        abrirEditarHabito(id);
    } else if (accion === 'archivar') {
        _agendaPushUndo && _agendaPushUndo();
        const h = window.agendaData.habitos.find(x => x.id === id);
        if (h) {
            h.archivado = true;
            guardarAgendaData();
            renderHabitosSection();
            _actualizarBadgeArchivadosHabitos();
        }
    } else if (accion === 'eliminar') {
        actEliminarDiario(id, 'habito');
    }
}

function _actualizarBadgeArchivadosHabitos() {
    const n = (window.agendaData?.habitos || []).filter(h => h.archivado).length;
    ['habitos-archive-badge','habitos-archive-badge-m'].forEach(bid => {
        const el = document.getElementById(bid);
        if (!el) return;
        if (n > 0) { el.style.display = 'flex'; el.textContent = n; }
        else { el.style.display = 'none'; }
    });
}

function abrirArchivadosHabitos() {
    const archivados = (window.agendaData?.habitos || []).filter(h => h.archivado);
    const prev = document.getElementById('_modalArchivadosHabitos');
    if (prev) prev.remove();
    const overlay = document.createElement('div');
    overlay.id = '_modalArchivadosHabitos';
    overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.7);z-index:10000;display:flex;align-items:center;justify-content:center;padding:16px;';
    overlay.innerHTML = `
        <div style="background:#0f172a;border:1px solid rgba(71,85,105,0.3);border-radius:20px;width:100%;max-width:520px;max-height:80vh;display:flex;flex-direction:column;">
            <div style="display:flex;align-items:center;justify-content:space-between;padding:20px 20px 14px;">
                <div style="display:flex;align-items:center;gap:10px;">
                    <span class="material-symbols-rounded" style="color:#64748b;font-size:20px;">archive</span>
                    <span style="color:#f1f5f9;font-size:15px;font-weight:800;">Hábitos archivados</span>
                </div>
                <button onclick="document.getElementById('_modalArchivadosHabitos').remove()" style="background:none;border:none;color:#64748b;cursor:pointer;padding:4px;">
                    <span class="material-symbols-rounded" style="font-size:20px;">close</span>
                </button>
            </div>
            <div style="overflow-y:auto;padding:0 16px 24px;flex:1;">
                ${archivados.length === 0
                    ? '<div style="text-align:center;color:#475569;font-size:13px;padding:40px 0;">No hay hábitos archivados</div>'
                    : archivados.map(h => {
                        const color = h.categoria?.color || '#10b981';
                        const icono = h.categoria?.icono || 'repeat';
                        return `<div style="display:flex;align-items:center;gap:12px;background:rgba(15,23,42,0.7);border:1px solid rgba(255,255,255,0.07);border-radius:14px;padding:12px 14px;margin-bottom:8px;">
                            <div style="width:36px;height:36px;border-radius:10px;background:${color};display:flex;align-items:center;justify-content:center;flex-shrink:0;">
                                <span class="material-symbols-rounded" style="color:white;font-size:18px;">${icono}</span>
                            </div>
                            <div style="flex:1;min-width:0;">
                                <div style="color:#f1f5f9;font-size:13px;font-weight:700;">${h.nombre}</div>
                                <div style="color:#64748b;font-size:11px;">${h.categoria?.nombre || ''}</div>
                            </div>
                            <button onclick="_desarchivarHabito('${h.id}')" style="background:rgba(16,185,129,0.1);border:1px solid rgba(16,185,129,0.3);border-radius:9px;color:#10b981;font-size:11px;font-weight:700;padding:6px 12px;cursor:pointer;">Restaurar</button>
                        </div>`;
                    }).join('')
                }
            </div>
        </div>`;
    document.body.appendChild(overlay);
    overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
}

function _desarchivarHabito(id) {
    const h = window.agendaData?.habitos?.find(x => x.id === id);
    if (h) {
        delete h.archivado;
        guardarAgendaData();
        renderHabitosSection();
        _actualizarBadgeArchivadosHabitos();
        const restantes = (window.agendaData?.habitos || []).filter(x => x.archivado);
        if (restantes.length === 0) {
            document.getElementById('_modalArchivadosHabitos')?.remove();
        } else {
            const contenido = document.querySelector('#_modalArchivadosHabitos [style*="overflow-y"]');
            if (contenido) {
                contenido.innerHTML = restantes.map(h => {
                    const color = h.categoria?.color || '#10b981';
                    const icono = h.categoria?.icono || 'repeat';
                    return `<div style="display:flex;align-items:center;gap:12px;background:rgba(15,23,42,0.7);border:1px solid rgba(255,255,255,0.07);border-radius:14px;padding:12px 14px;margin-bottom:8px;">
                        <div style="width:36px;height:36px;border-radius:10px;background:${color};display:flex;align-items:center;justify-content:center;flex-shrink:0;">
                            <span class="material-symbols-rounded" style="color:white;font-size:18px;">${icono}</span>
                        </div>
                        <div style="flex:1;min-width:0;">
                            <div style="color:#f1f5f9;font-size:13px;font-weight:700;">${h.nombre}</div>
                            <div style="color:#64748b;font-size:11px;">${h.categoria?.nombre || ''}</div>
                        </div>
                        <button onclick="_desarchivarHabito('${h.id}')" style="background:rgba(16,185,129,0.1);border:1px solid rgba(16,185,129,0.3);border-radius:9px;color:#10b981;font-size:11px;font-weight:700;padding:6px 12px;cursor:pointer;">Restaurar</button>
                    </div>`;
                }).join('');
            }
        }
    }
}
