    inicio.setHours(0,0,0,0);
    const fin = habito.fechaFin ? new Date(habito.fechaFin) : new Date(inicio); 
    if (!habito.fechaFin) fin.setFullYear(fin.getFullYear() + 1);
    const totalSemanas = Math.max(1, Math.ceil((fin - inicio) / (7 * 86400000)));
    const semanasTransc = Math.max(0, Math.ceil((hoy - inicio) / (7 * 86400000)));
    const pctProgreso = Math.min(100, Math.round((semanasTransc / totalSemanas) * 100));
