function _abrirHitoLogrado(dias, el) {
    const habitoId = window._estHabitoActual || null;
    const habito = habitoId
        ? (window.agendaData.habitos || []).find(h => h.id === habitoId)
        : null;
    const nombre = habito ? habito.nombre : '';
    const svgEl = el ? el.querySelector('svg') : null;
    const svgStr = svgEl ? svgEl.outerHTML : '';
    if (typeof mostrarCelebracionRacha === 'function') {
        mostrarCelebracionRacha(dias, svgStr, nombre);
    }
}
window._timePickerHora = null;

